import{_ as t,o as a,c as o,S as s}from"./chunks/framework.DZlzLDBr.js";const p=JSON.parse('{"title":"Widget","description":"","frontmatter":{},"headers":[],"relativePath":"Widget.md","filePath":"Widget.md","lastUpdated":null}'),r={name:"Widget.md"};function i(d,e,n,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="widget" tabindex="-1">Widget <a class="header-anchor" href="#widget" aria-label="Permalink to &quot;Widget&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Sprout widget is a sidebar panel for quick access to decks and study sessions.</p><p>It shows a deck tree with counts and lets you start studying in one click.</p><h2 id="opening-the-widget" tabindex="-1">Opening the widget <a class="header-anchor" href="#opening-the-widget" aria-label="Permalink to &quot;Opening the widget&quot;">​</a></h2><p>Click the Sprout icon in Obsidian&#39;s left sidebar to open or close the widget.</p><h2 id="deck-tree" tabindex="-1">Deck tree <a class="header-anchor" href="#deck-tree" aria-label="Permalink to &quot;Deck tree&quot;">​</a></h2><p>The widget displays your decks as a collapsible tree. Each deck shows:</p><ul><li><strong>Deck name</strong></li><li><strong>Due count</strong> — Number of cards due for review</li><li><strong>New count</strong> — Number of new cards available</li></ul><p>Click a deck to start a study session for that scope.</p><h2 id="scope-modes" tabindex="-1">Scope modes <a class="header-anchor" href="#scope-modes" aria-label="Permalink to &quot;Scope modes&quot;">​</a></h2><p>Choose a mode in the widget header:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Folder</strong></td><td>Decks are organised by the folder structure of your vault. Each folder containing notes with cards becomes a deck.</td></tr><tr><td><strong>Note</strong></td><td>Each note with cards is shown as a separate deck.</td></tr></tbody></table><p>Switching mode changes how decks are grouped, but does not change card data.</p><h2 id="folder-notes-as-decks" tabindex="-1">Folder notes as decks <a class="header-anchor" href="#folder-notes-as-decks" aria-label="Permalink to &quot;Folder notes as decks&quot;">​</a></h2><p>When <strong>Treat folder notes as decks</strong> is enabled, a folder note becomes the deck root for that folder.</p><p>Its cards are grouped with other cards from the same folder.</p><h2 id="starting-a-session" tabindex="-1">Starting a session <a class="header-anchor" href="#starting-a-session" aria-label="Permalink to &quot;Starting a session&quot;">​</a></h2><p>Click any deck in the widget tree to immediately start a study session scoped to that deck. The session opens in the main content area.</p><h2 id="summary-view" tabindex="-1">Summary view <a class="header-anchor" href="#summary-view" aria-label="Permalink to &quot;Summary view&quot;">​</a></h2><p>After completing a session, the widget shows a summary:</p><ul><li>Cards reviewed</li><li>Time spent</li><li>Accuracy (percentage of Good/Easy grades)</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>The widget is most useful when pinned to the sidebar for quick access between notes.</li><li>Use <strong>Folder</strong> mode if your vault is organised by subject/topic folders.</li><li>Use <strong>Note</strong> mode if you want to study individual notes.</li></ul>',25)])])}const g=t(r,[["render",i]]);export{p as __pageData,g as default};
